function toDomainSeparator(
    bytes1 fields,
    bytes32 nameHash,
    bytes32 versionHash,
    uint256 chainId,
    address verifyingContract,
    bytes32 salt
) internal pure returns (bytes32 hash) {
    bytes32 domainTypeHash = toDomainTypeHash(fields);

    assembly ("memory-safe") {
        // align fields to the right for easy processing
        fields := shr(248, fields)

        // FMP used as scratch space
        let fmp := mload(0x40)
        mstore(fmp, domainTypeHash)

        let ptr := add(fmp, 0x20)
        if and(fields, 0x01) {
            mstore(ptr, nameHash)
            ptr := add(ptr, 0x20)
        }
        if and(fields, 0x02) {
            mstore(ptr, versionHash)
            ptr := add(ptr, 0x20)
        }
        if and(fields, 0x04) {
            mstore(ptr, chainId)
            ptr := add(ptr, 0x20)
        }
        if and(fields, 0x08) {
            mstore(ptr, verifyingContract)
            ptr := add(ptr, 0x20)
        }
        if and(fields, 0x10) {
            mstore(ptr, salt)
            ptr := add(ptr, 0x20)
        }

        hash := keccak256(fmp, sub(ptr, fmp))
    }
}

function areValidSignaturesNow(
    bytes32 hash,
    bytes[] memory signers,
    bytes[] memory signatures
) internal view returns (bool) {
    if (signers.length != signatures.length) return false;

    bytes32 lastId = bytes32(0);

    for (uint256 i = 0; i < signers.length; ++i) {
        bytes memory signer = signers[i];

        // If one of the signatures is invalid, reject the batch
        if (!isValidSignatureNow(signer, hash, signatures[i])) return false;

        bytes32 id = keccak256(signer);
        // If the current signer ID is greater than all previous IDs, then this is a new signer.
        if (lastId < id) {
            lastId = id;
        } else {
            // If this signer id is not greater than all the previous ones, verify that it is not a duplicate of a previous one
            // This loop is never executed if the signers are ordered by id.
            for (uint256 j = 0; j < i; ++j) {
                if (id == keccak256(signers[j])) return false;
            }
        }
    }

    return true;
}

function _isValidNestedTypedDataSignature(
    bytes32 hash,
    bytes calldata encodedSignature
) private view returns (bool) {
    // decode signature
    (
        bytes calldata signature,
        bytes32 appSeparator,
        bytes32 contentsHash,
        string calldata contentsDescr
    ) = encodedSignature.decodeTypedDataSig();

    (
        ,
        string memory name,
        string memory version,
        uint256 chainId,
        address verifyingContract,
        bytes32 salt,

    ) = eip712Domain();

    // Check that contentHash and separator are correct
    // Rebuild nested hash
    return
        hash == appSeparator.toTypedDataHash(contentsHash) &&
        bytes(contentsDescr).length != 0 &&
        _rawSignatureValidation(
            appSeparator.toTypedDataHash(
                ERC7739Utils.typedDataSignStructHash(
                    contentsDescr,
                    contentsHash,
                    abi.encode(keccak256(bytes(name)), keccak256(bytes(version)), chainId, verifyingContract, salt)
                )
            ),
            signature
        );
}

function readList(Memory.Slice item) internal pure returns (Memory.Slice[] memory list) {
    uint256 itemLength = item.length();

    (uint256 listOffset, uint256 listLength, ItemType itemType) = _decodeLength(item);
    require(itemType == ItemType.List && itemLength == listOffset + listLength, RLPInvalidEncoding());

    // Start a buffer in the unallocated space
    uint256 ptr;
    assembly ("memory-safe") {
        list := mload(0x40)
        ptr := add(list, 0x20)
    }

    // Get all items in order, and push them to the buffer
    for (uint256 currentOffset = listOffset; currentOffset < itemLength; ptr += 0x20) {
        (uint256 elementOffset, uint256 elementLength, ) = _decodeLength(item.slice(currentOffset));
        Memory.Slice element = item.slice(currentOffset, elementLength + elementOffset);
        currentOffset += elementOffset + elementLength;

        // Write item to the buffer
        assembly ("memory-safe") {
            mstore(ptr, element)
        }
    }

    // write list length and reserve space
    assembly ("memory-safe") {
        mstore(list, div(sub(ptr, add(list, 0x20)), 0x20))
        mstore(0x40, ptr)
    }
}
